import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';
import { TEMPLATES } from '../data/staticData';
import { CheckCircle, Plus, ArrowRight, Sparkles } from 'lucide-react';
import './TemplatesPage.css';

const TemplateCard = ({ template, isSelected, onSelect }) => (
  <div
    className={`template-card ${isSelected ? 'selected' : ''} ${template.isCustom ? 'custom-card' : ''}`}
    onClick={() => onSelect(template.id)}
  >
    {isSelected && (
      <div className="selected-badge">
        <CheckCircle size={16} /> Selected
      </div>
    )}

    <div className="template-preview" style={{ '--template-accent': template.accent }}>
      {template.isCustom ? (
        <div className="custom-preview">
          <Plus size={32} />
          <span>Create Custom</span>
        </div>
      ) : (
        <TemplatePreviewMini template={template} />
      )}
    </div>

    <div className="template-info">
      <div className="template-name-row">
        <h3 className="template-name">{template.name}</h3>
        <div className="template-dot" style={{ background: template.accent }} />
      </div>
      <p className="template-desc">{template.description}</p>
      <div className="template-tags">
        {template.tags.map(t => (
          <span key={t} className={`template-tag ${t === 'ATS-Ready' ? 'tag-ats' : 'tag-other'}`}>{t}</span>
        ))}
      </div>
    </div>
  </div>
);

const TemplatePreviewMini = ({ template }) => {
  const colors = {
    classic: (
      <div className="mini-classic">
        <div className="mini-sidebar" style={{ background: template.accent }} />
        <div className="mini-content">
          <div className="mini-line lg" />
          <div className="mini-line md" />
          <div className="mini-divider" />
          <div className="mini-line sm" />
          <div className="mini-line sm" />
          <div className="mini-line sm" />
        </div>
      </div>
    ),
    modern: (
      <div className="mini-modern">
        <div className="mini-top-bar" style={{ background: template.accent }} />
        <div className="mini-content-full">
          <div className="mini-line lg center" />
          <div className="mini-line md center" />
          <div className="mini-divider" />
          <div className="mini-line sm" />
          <div className="mini-line sm" />
        </div>
      </div>
    ),
    bold: (
      <div className="mini-bold">
        <div className="mini-bold-header" style={{ background: template.accent }}>
          <div className="mini-line lg white" />
          <div className="mini-line sm white" />
        </div>
        <div className="mini-content-full" style={{ padding: '8px' }}>
          <div className="mini-line sm" />
          <div className="mini-line sm" />
        </div>
      </div>
    ),
    clean: (
      <div className="mini-clean">
        <div className="mini-line lg" style={{ borderBottom: `2px solid ${template.accent}`, paddingBottom: 4 }} />
        <div className="mini-section-label" style={{ color: template.accent }} />
        <div className="mini-line sm" />
        <div className="mini-line sm" />
        <div className="mini-section-label" style={{ color: template.accent }} />
        <div className="mini-line sm" />
      </div>
    ),
    gradient: (
      <div className="mini-gradient">
        <div className="mini-grad-sidebar" style={{ background: `linear-gradient(180deg, ${template.accent}, #fff2)` }} />
        <div className="mini-content">
          <div className="mini-line lg" />
          <div className="mini-line md" />
          <div className="mini-line sm" />
          <div className="mini-line sm" />
        </div>
      </div>
    ),
    executive: (
      <div className="mini-executive">
        <div className="mini-exec-top" style={{ borderTop: `4px solid ${template.accent}` }}>
          <div className="mini-line lg center" style={{ marginTop: 8 }} />
          <div className="mini-line md center" />
        </div>
        <div className="mini-two-col">
          <div className="mini-col-sm">
            <div className="mini-line sm" />
            <div className="mini-line sm" />
          </div>
          <div className="mini-col-lg">
            <div className="mini-line sm" />
            <div className="mini-line sm" />
          </div>
        </div>
      </div>
    ),
  };
  return colors[template.id] || colors.modern;
};

const TemplatesPage = () => {
  const navigate = useNavigate();
  const { selectedTemplate, setSelectedTemplate } = useApp();

  const handleSelect = (id) => {
    setSelectedTemplate(id);
  };

  const handleContinue = () => {
    if (!selectedTemplate) return;
    navigate('/builder');
  };

  return (
    <div className="templates-page">
      <div className="container">
        <div className="templates-header">
          <div className="section-eyebrow">
            <Sparkles size={13} /> Step 1 of 3
          </div>
          <h1 className="templates-title">Choose Your Template</h1>
          <p className="templates-subtitle">
            Select from our professionally designed ATS-ready templates, or create your own from scratch.
          </p>
        </div>

        <div className="templates-grid">
          {TEMPLATES.map(template => (
            <TemplateCard
              key={template.id}
              template={template}
              isSelected={selectedTemplate === template.id}
              onSelect={handleSelect}
            />
          ))}
        </div>

        <div className="templates-footer">
          {selectedTemplate && (
            <div className="selected-info animate-fadeIn">
              <CheckCircle size={18} color="var(--success)" />
              <span>
                <strong>{TEMPLATES.find(t => t.id === selectedTemplate)?.name}</strong> selected
              </span>
            </div>
          )}
          <button
            className="btn-primary continue-btn"
            onClick={handleContinue}
            disabled={!selectedTemplate}
          >
            Continue to Builder <ArrowRight size={17} />
          </button>
        </div>
      </div>
    </div>
  );
};

export default TemplatesPage;
